              "sourceY": {"expr": "scale('yscale', datum.datum.source.y)"},
              "targetX": {"expr": "scale('xscale', datum.datum.target.x)"},
              "targetY": {"expr": "scale('yscale', datum.datum.target.y)"}
              },
