          },
          {
          "type": "text",     // file title for enrichment
          "from": {"data": "links"},
            "encode": {
              "enter": {
                // "align": {"value": "left"},
                "baseline": {"value": "top"},
                // "fill": {"value": "white"}, //JCR, changes color of IPs addrs in enrichment box that appear on link hover. Removing hardcoded colo lets it change with the Malcolm theme
                "opacity": {"value": 0},
